// Adaptar caption por plataforma
const input = $input.first().json.body;
const caption = input.caption;
const imagePrompt = input.image_prompt || null;
const platforms = input.platforms || ['facebook', 'instagram', 'x', 'linkedin'];
const hashtags = input.hashtags || [];
const ctaWhatsapp = input.cta_whatsapp || 'wa.me/526671326265';

// Generar versiones por plataforma
const hashtagStr = hashtags.length > 0 ? '\n\n' + hashtags.map(h => '#' + h).join(' ') : '';

const adapted = {
  original: caption,
  platforms: platforms,
  image_prompt: imagePrompt,
  captions: {
    facebook: caption + '\n\n' + '\uD83D\uDCF2 ' + ctaWhatsapp + hashtagStr,
    instagram: caption + hashtagStr + '\n\n\uD83D\uDCF2 Link en bio',
    x: caption.substring(0, 250) + (caption.length > 250 ? '...' : '') + (hashtags.length > 0 ? ' ' + hashtags.slice(0, 2).map(h => '#' + h).join(' ') : ''),
    linkedin: caption + '\n\n' + '\u27A1\uFE0F ' + ctaWhatsapp + hashtagStr,
    tiktok: caption + hashtagStr,
    threads: caption.substring(0, 500),
    pinterest: caption.substring(0, 500) + hashtagStr,
    bluesky: caption.substring(0, 300)
  }
};

// Asegurar X no exceda 280 chars
if (adapted.captions.x.length > 280) {
  adapted.captions.x = adapted.captions.x.substring(0, 277) + '...';
}

return [{ json: adapted }];

// Preparar payload para Blotato API
const captions = $('Adapt Captions').first().json.captions;
const platforms = $('Adapt Captions').first().json.platforms;
const imageData = $json.predictions ? $json.predictions[0].bytesBase64Encoded : null;

const posts = platforms.map(platform => {
  return {
    platform: platform,
    caption: captions[platform] || captions.facebook,
    image_base64: imageData,
    scheduled: false // publicar inmediatamente
  };
});

return posts.map(p => ({ json: p }));

// Preparar payload sin imagen
const captions = $('Adapt Captions').first().json.captions;
const platforms = $('Adapt Captions').first().json.platforms;

const posts = platforms.map(platform => {
  return {
    platform: platform,
    caption: captions[platform] || captions.facebook,
    image_base64: null,
    scheduled: false
  };
});

return posts.map(p => ({ json: p }));
